func solve(n int64, k int64) int64 {
	if k == 0 {
		return 0
	}
	if k == 1 {
		// Count numbers with popcount-depth exactly 1
		// These are numbers with exactly 1 bit set (powers of 2)
		count := 0
		for power := int64(1); power <= n; power *= 2 {
			count++
		}
		return int64(count)
	}
	// For k >= 2, we need to find numbers whose popcount-depth is exactly k
	// We can use BFS to find all numbers with popcount-depth exactly k
	// and count how many of them are <= n
	// We start from numbers with popcount 1 (since the first step of the sequence is popcount)
	// and then simulate the sequence steps
	// We use a queue to perform BFS
	// We also use a visited map to avoid revisiting numbers
	visited := make(map[int64]bool)
	queue := []int64{}
	// Initialize the queue with numbers that have popcount 1
	for power := int64(1); power <= n; power *= 2 {
		queue = append(queue, power)
	}
	// We also need to include numbers that have popcount 1 but are larger than n
	// but since we are only considering numbers <= n, we don't need to do that
	// Now perform BFS
	// We also need to track the depth of each number
	// We use a map to track the depth of each number
	depthMap := make(map[int64]int64)
	// Initialize the depth map
	for _, num := range queue {
		depthMap[num] = 1
	}
	// Now perform BFS
	for len(queue) > 0 {
		num := queue[0]
		queue = queue[1:]
		// If the current number has depth k, we count it
		if depthMap[num] == k {
			continue
		}
		// Get the popcount of the current number
		popCount := popCount(num)
		// If the popcount is 0, we can't proceed further
		if popCount == 0 {
			continue
		}
		// If the depth is already k, we don't need to process further
		if depthMap[num] >= k {
			continue
		}
		// If the next number is not in the map, we add it to the queue
		nextNum := popCount
		if !visited[nextNum] {
			visited[nextNum] = true
			depthMap[nextNum] = depthMap[num] + 1
			queue = append(queue, nextNum)
		}
	}
	// Now count how many numbers have depth exactly k
	count := 0
	for num := range depthMap {
		if depthMap[num] == k {
			if num <= n {
				count++
			}
		}
	}
	return int64(count)
}

// popCount returns the number of 1 bits in the binary representation of x
func popCount(x int64) int64 {
	count := 0
	for x > 0 {
		count += x & 1
		x >>= 1
	}
	return int64(count)
}
