func solve(n int64, k int64) int64 {
	if k == 0 {
		return 0
	}
	if k == 1 {
		// Count numbers with binary representation of 1 followed by zeros
		// These numbers will have popcount-depth 1
		count := 0
		for i := 1; i <= n; i *= 2 {
			if i > n {
				break
			}
			count++
		}
		return int64(count)
	}
	// For k >= 2, we need to find numbers whose popcount-depth is exactly k
	// We can use BFS to find all numbers with popcount-depth exactly k
	// and count how many are <= n
	visited := make(map[int64]bool)
	queue := []int64{1}
	depth := 0
	for depth < k {
		nextQueue := []int64{}
		for _, num := range queue {
			if visited[num] {
				continue
			}
			visited[num] = true
			popCount := popCount(num)
			if popCount == 1 {
				// This number has popcount-depth equal to depth + 1
				// If depth + 1 == k, we need to count it
				if depth+1 == k {
					if num <= n {
						count++
					}
				}
			}
			nextQueue = append(nextQueue, int64(popCount))
		}
		queue = nextQueue
		depth++
	}
	return int64(count)
}

func popCount(x int64) int {
	count := 0
	for x > 0 {
		count += int(x & 1)
		x >>= 1
	}
	return count
}
